const items = $input.all();

const retrievedDocuments = items.map((item, index) => {
  const document = item.json.document || {};
  const metadata = document.metadata || {};
  const pageContent = document.pageContent || "";
  const score = item.json.score ?? null;

  return {
    rank: index + 1,
    score,
    chunk_id: metadata.chunk_id || null,
    document_title: metadata.document_title || null,
    section_path: metadata.section_path || null,
    statut_document: metadata.statut_document || null,
    validation: metadata.validation || null,
    content: pageContent
  };
});

return [
  {
    json: {
      question: $("SET - Normalize Website Question").first().json.question,
      session_id: $("SET - Normalize Website Question").first().json.session_id,
      mode: "controlled_chatbot",
      source: "website",
      public_chatbot: false,
      source_collection: "pilat_validated_doctrine_v1",
      retrieved_count: retrievedDocuments.length,
      retrieved_documents: JSON.stringify(retrievedDocuments, null, 2),
      doctrine_rule: "SCENARIO != MEASURED",
      fallback_message: $("SET - Normalize Website Question").first().json.fallback_message,
      decision_retrieval: retrievedDocuments.length > 0 ? "GO" : "HOLD"
    }
  }
];

const current = $input.first().json || {};

function safeNode(name) {
  try {
    return $(name).first().json || {};
  } catch (error) {}

  try {
    return $items(name, 0, 0)[0]?.json || {};
  } catch (error) {}

  return {};
}

function firstDefined(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== '') {
      return value;
    }
  }
  return '';
}

function asText(value) {
  if (value === undefined || value === null) return '';

  if (typeof value === 'string') return value.trim();

  if (typeof value === 'number' || typeof value === 'boolean') {
    return String(value);
  }

  if (Array.isArray(value)) {
    return value.map(asText).filter(Boolean).join('\n').trim();
  }

  if (typeof value === 'object') {
    return asText(
      firstDefined(
        value.answer,
        value.output,
        value.text,
        value.content,
        value.message?.content,
        value.response?.answer,
        value.response?.output,
        value.response?.text,
        value.response?.content,
        value.choices?.[0]?.message?.content
      )
    );
  }

  return '';
}

function extractAnswer(...objects) {
  for (const obj of objects) {
    const answer = asText(
      firstDefined(
        obj.answer,
        obj.output,
        obj.text,
        obj.response,
        obj.result,
        obj.message?.content,
        obj.choices?.[0]?.message?.content,
        obj.data?.answer,
        obj.data?.output
      )
    );

    if (answer) return answer;
  }

  return '';
}

function retrievedCountFrom(obj) {
  const directCount = firstDefined(
    obj.retrieved_count,
    obj.retrievedCount,
    obj.matches_count,
    obj.count
  );

  if (directCount !== '') {
    const parsed = Number(directCount);
    if (Number.isFinite(parsed)) return parsed;
  }

  for (const key of ['retrieved', 'matches', 'documents', 'chunks', 'sources', 'results']) {
    if (Array.isArray(obj[key])) return obj[key].length;
  }

  return 0;
}

const normalized = safeNode('SET - Normalize Website Question');
const retrieved = safeNode('CODE - Build Retrieved Context');
const aiAnswer = safeNode('AI - Controlled PILAT Answer');
const modelAnswer = safeNode('MODEL - OpenAI Controlled Answer');

let generatedSessionId = `pilat-${Date.now()}`;
try {
  if ($execution?.id) {
    generatedSessionId = `pilat-${$execution.id}`;
  }
} catch (error) {}

const sessionId = asText(
  firstDefined(
    normalized.session_id,
    normalized.body?.session_id,
    current.session_id,
    current.body?.session_id,
    generatedSessionId
  )
);

const question = asText(
  firstDefined(
    normalized.question,
    normalized.body?.question,
    current.question,
    current.body?.question
  )
);

const answer = extractAnswer(current, aiAnswer, modelAnswer);

const retrievedCount =
  retrievedCountFrom(retrieved) ||
  retrievedCountFrom(current);

return [
  {
    json: {
      status: 'GO',
      mode: 'controlled_chatbot',
      public_chatbot: false,
      source: 'website',
      session_id: sessionId,
      question,
      answer,
      source_collection: 'pilat_validated_doctrine_v1',
      doctrine_rule: 'SCENARIO != MEASURED',
      retrieved_count: retrievedCount,
      decision: 'GO for controlled website chatbot test; HOLD public release'
    }
  }
];
